INSERT INTO modelo_veiculo (nome, id_marca, id_tipo) SELECT nome, m.id, t.id FROM UNNEST(ARRAY[ 'Onix', 'Prisma', 'Celta', 'Corsa', 'Cruze', 'Vectra', 'Astra', 'Opala', 'Omega', 'Monza', 'Kadett', 'Chevette', 'Classic', 'Agile', 'Meriva' ]) AS nome CROSS JOIN (SELECT id FROM marca_veiculo WHERE UPPER(nome) = 'CHEVROLET') m CROSS JOIN (SELECT id FROM tipo_veiculo WHERE UPPER(descricao) = 'CARRO') t;
